fn max_sum_subarray(nums: &[i32], k: usize) -> i32 {
    let mut window: i32 = nums[..k].iter().sum();
    let mut best = window;
    for i in k..nums.len() {
        window += nums[i] - nums[i - k];
        best = best.max(window);
    }
    best
}

fn main() {
    println!("{}", max_sum_subarray(&[2, 1, 5, 1, 3, 2], 3));  // 9
}

