fn two_sum_sorted(nums: &[i32], target: i32) -> Option<(usize, usize)> {
    let (mut left, mut right) = (0, nums.len() - 1);
    while left < right {
        let s = nums[left] + nums[right];
        if s == target {
            return Some((left, right));
        } else if s < target {
            left += 1;
        } else {
            right -= 1;
        }
    }
    None
}

fn main() {
    println!("{:?}", two_sum_sorted(&[1, 3, 5, 7, 10], 8));
    // Some((0, 4))
}

