fn permute(nums: &[i32], path: &mut Vec<i32>, used: &mut Vec<bool>, result: &mut Vec<Vec<i32>>) {
    if path.len() == nums.len() {
        result.push(path.clone());
        return;
    }
    for i in 0..nums.len() {
        if used[i] { continue; }
        used[i] = true;
        path.push(nums[i]);
        permute(nums, path, used, result);
        path.pop();
        used[i] = false;
    }
}

